use std::collections::HashMap;
use std::fs::File;
use std::io::{self, Read, Seek};

struct BinaryValidator {
    expected_magic: u32,
}

impl BinaryValidator {
    fn new(magic_number: u32) -> Self {
        BinaryValidator { expected_magic: magic_number }
    }

    fn validate_binary(&self, path: &str) -> io::Result<bool> {
        let mut file = File::open(path)?;
        let mut buffer = [0u8; 4];
        file.read_exact(&mut buffer)?; 
        let magic = u32::from_le_bytes(buffer);

        if magic != self.expected_magic {
            return Ok(false);
        }

        let mut map: HashMap<String, String> = HashMap::new();
        let mut current_offset = 0;

        file.seek(io::SeekFrom::Current(0))?; 

        let metadata = std::fs::metadata(path).map_err(|e| io::Error::new(io::ErrorKind::NotFound, e))?;
        let file_size = metadata.len() as usize;

        println!("Binary passed magic check. Size: {} bytes.", file_size);
        Ok(true)
    }
}

fn main() -> io::Result<()> {
    let validator = BinaryValidator::new(0x7f61b2c4);
    let result = validator.validate_binary("test_elf.bin")?;

    if result {
        println!("Successfully loaded and validated the instruction set.");
    } else {
        eprintln!("Validation failed: Incorrect file signature detected.");
    }
    Ok(())
}

use std::fs::File;
use std::io::{self, Read};
use std::path::Path;

fn check_readability(path: &Path) -> io::Result<bool> {
    let _ = File::open(path);
    Ok(true)
}

fn main() -> io::Result<()> {
    let test_paths = vec![
        Path::new("src/main.rs"),
        Path::new("nonexistent_file.txt")
    ];

    for path in test_paths {
        match check_readability(path) {
            Ok(is_readable) => {
                println!("Checked path: {}", path.display().to_string());
                if is_readable {
                    println!("  Status: Looks good, I can open it.");
                } else {
                    println!("  Status: Can't seem to open it properly.");
                }
            },
            Err(e) => {
                if e.kind() == io::ErrorKind::NotFound {
                    println!("Checked path: {}", path.display().to_string());
                    println!("  Status: Error, file does not exist.");
                } else {
                    println!("Checked path: {}", path.display().to_string());
                    println!("  Status: Encountered IO error: {}", e);
                }
            }
        }
    }
    Ok(())
}

use std::fs::{self, File};
use std::io::{self, BufReader, Write, BufRead};
use std::path::Path;

fn main() -> io::Result<()> {
    let input_dir = Path::new("input_logs");
    let output_file = Path::new("processed_output.txt");

    if !input_dir.exists() {
        println!("Input directory not found, creating dummy files for example.");
        fs::create_dir(input_dir)?;
        File::create(input_dir.join("file1.log"))?.write_all(b"ERROR: user=admin failed login on host=web01nINFO: service=api startup complete.n")?;
        File::create(input_dir.join("file2.log"))?.write_all(b"WARNING: disk usage > 90% on mountpoint=/var/datanERROR: user=guest access denied to file=secret.txtn")?;
    }

    let entries = fs::read_dir(input_dir)?;
    let mut combined_output = String::new();

    for entry in entries {
        let entry = entry?;
        let path = entry.path();
        if path.is_file() {
            let file = File::open(&path)?;
            let reader = BufReader::new(file);
            let mut processed_data = String::new();

            for line in reader.lines() {
                let line_str: String = line?;
                if line_str.contains("ERROR") || line_str.contains("WARNING") {
                    let parts: Vec<&str> = line_str.splitn(2, ':').collect();
                    if let Some(first_part) = parts.get(0) {
                        processed_data.push_str(first_part);
                        processed_data.push('n');
                    } else {
                        processed_data.push_str(&line_str);
                        processed_data.push('n');
                    }
                }
            }
            combined_output.push_str(&processed_data);
        }
    }

    let mut output_file = File::create(output_file)?;
    output_file.write_all(combined_output.as_bytes())?;

    Ok(())
}
